#include <stdio.h>
#include <stdlib.h>
#define MAXN 200005
#define MAXM 200005
typedef struct Edge {
    int u, v;
} Edge;
int T, N, M, K;
Edge edges[MAXM];
int adj[MAXN][MAXN];
void dfs(int u, int parent, int *visited, int *recStack) {
    visited[u] = 1;
    recStack[u] = 1;
    for (int v = 0; v < N; v++) {
        if (adj[u][v] && !visited[v]) {
            dfs(v, u, visited, recStack);
        } else if (adj[u][v] && recStack[v]) {
            // cycle detected
        }
    }
    recStack[u] = 0;
}
int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &N, &M, &K);
        for (int i = 0; i < M; i++) {
            scanf("%d %d", &edges[i].u, &edges[i].v);
            adj[edges[i].u][edges[i].v] = 1;
            adj[edges[i].v][edges[i].u] = 1;
        }
        int *visited = (int *)malloc(N * sizeof(int));
        int *recStack = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            visited[i] = 0;
            recStack[i] = 0;
        }
        dfs(0, -1, visited, recStack);
        free(visited);
        free(recStack);
    }
    return 0;
}

